import { type GetCounter } from 'wasp/server/operations';

export const getCounter: GetCounter<void, { id: number; count: number }> = async (args, context) => {
  let counter = await context.entities.Counter.findFirst();
  if (!counter) {
    counter = await context.entities.Counter.create({
      data: {
        count: 0
      }
    });
  }
  return counter;
};

