import { type Increment, type Decrement } from 'wasp/server/operations';

export const increment: Increment<void, { id: number; count: number }> = async (args, context) => {
  let counter = await context.entities.Counter.findFirst();
  if (!counter) {
    counter = await context.entities.Counter.create({
      data: { count: 0 }
    });
  }
  return context.entities.Counter.update({
    where: { id: counter.id },
    data: { count: counter.count + 1 }
  });
};

export const decrement: Decrement<void, { id: number; count: number }> = async (args, context) => {
  let counter = await context.entities.Counter.findFirst();
  if (!counter) {
    counter = await context.entities.Counter.create({
      data: { count: 0 }
    });
  }
  return context.entities.Counter.update({
    where: { id: counter.id },
    data: { count: counter.count - 1 }
  });
};

