import { useQuery, useAction, getCounter, increment, decrement } from 'wasp/client/operations';

export const MainPage = () => {
  const { data: counter, isLoading, error } = useQuery(getCounter);
  const incrementAction = useAction(increment);
  const decrementAction = useAction(decrement);

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {error.message}</div>;

  return (
    <div style={{ textAlign: 'center', marginTop: '50px' }}>
      <h1>Wasp Counter</h1>
      <div style={{ fontSize: '2rem', margin: '20px' }}>
        Count: {counter?.count}
      </div>
      <div>
        <button 
          onClick={() => decrementAction()} 
          style={{ padding: '10px 20px', fontSize: '1rem', marginRight: '10px' }}
        >
          Decrement
        </button>
        <button 
          onClick={() => incrementAction()} 
          style={{ padding: '10px 20px', fontSize: '1rem' }}
        >
          Increment
        </button>
      </div>
    </div>
  );
};

